// Get HTTP response
const resp = $input.item.json;
const pageData = $('Get Pages to Monitor').item.json;
const checkedAt = new Date().toISOString().split('T')[0];

// Detect HTTP errors
if (resp.error || resp.statusCode >= 400 || resp.status >= 400) {
  return {
    url: pageData.url,
    page_name: pageData.page_name,
    new_content: '', old_content: '',
    old_content_for_ai: '', new_content_for_ai: '',
    changed: false, is_first_run: false,
    error: 'HTTP error: ' + (resp.error?.message || resp.statusCode || resp.status || 'unknown'),
    checked_at: checkedAt
  };
}

// Get response body
let html = '';
if (typeof resp.data === 'string') html = resp.data;
else if (typeof resp.body === 'string') html = resp.body;
else if (typeof resp === 'string') html = resp;
else html = JSON.stringify(resp);

// Check for Cloudflare/bot challenges
if (html.includes('Enable JavaScript and cookies') || html.includes('cf-challenge') || html.includes('_cf_chl')) {
  return {
    url: pageData.url,
    page_name: pageData.page_name,
    new_content: '', old_content: '',
    old_content_for_ai: '', new_content_for_ai: '',
    changed: false, is_first_run: false,
    error: 'Page is behind Cloudflare bot protection - use a different URL',
    checked_at: checkedAt
  };
}

// Check for empty/tiny responses
if (!html || html.length < 200) {
  return {
    url: pageData.url,
    page_name: pageData.page_name,
    new_content: '', old_content: '',
    old_content_for_ai: '', new_content_for_ai: '',
    changed: false, is_first_run: false,
    error: 'Page returned empty or very short content',
    checked_at: checkedAt
  };
}

// Strip HTML tags to get plain text
let text = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/&lt;/gi, '<')
  .replace(/&gt;/gi, '>')
  .replace(/&#\d+;/gi, '')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 40000);

// Compare with previously stored content
const oldContent = (pageData.last_content || '').trim();
const isFirstRun = oldContent === '';
const changed = !isFirstRun && oldContent !== text;

// Build smart AI context: find WHERE the texts differ
let oldForAi = oldContent.substring(0, 10000);
let newForAi = text.substring(0, 10000);

if (changed && oldContent.length > 0) {
  // Find first point of difference
  let diffStart = 0;
  const minLen = Math.min(oldContent.length, text.length);
  for (let i = 0; i < minLen; i++) {
    if (oldContent[i] !== text[i]) {
      diffStart = i;
      break;
    }
    if (i === minLen - 1) diffStart = minLen;
  }

  // Take context: 500 chars before diff, then 4500 chars after
  const contextBefore = Math.max(0, diffStart - 500);
  const prefix = contextBefore > 0 ? '...[IDENTICAL CONTENT SKIPPED]... ' : '';

  const oldDiffSection = prefix + oldContent.substring(contextBefore, contextBefore + 5000);
  const newDiffSection = prefix + text.substring(contextBefore, contextBefore + 5000);

  // Also grab the tail end of both texts (last 3000 chars)
  const oldTail = oldContent.length > 5000 ? '\n\n...[SKIPPING TO END]...\n' + oldContent.substring(oldContent.length - 3000) : '';
  const newTail = text.length > 5000 ? '\n\n...[SKIPPING TO END]...\n' + text.substring(text.length - 3000) : '';

  oldForAi = (oldDiffSection + oldTail).substring(0, 12000);
  newForAi = (newDiffSection + newTail).substring(0, 12000);

  // Add length comparison as context
  oldForAi = '[Total length: ' + oldContent.length + ' chars]\n' + oldForAi;
  newForAi = '[Total length: ' + text.length + ' chars]\n' + newForAi;
}

return {
  url: pageData.url,
  page_name: pageData.page_name,
  new_content: text,
  old_content: oldContent,
  old_content_for_ai: oldForAi,
  new_content_for_ai: newForAi,
  changed: changed,
  is_first_run: isFirstRun,
  checked_at: checkedAt
};

// Get AI summaries and build email bodies
const items = $input.all();
const results = [];

for (const item of items) {
  const summary = item.json.text || item.json.output || 'No summary available';
  const p = $('Extract & Compare').item.json;

  const body = '<h2>TOS Change Detected</h2>' +
    '<p><strong>Page:</strong> ' + p.page_name + '</p>' +
    '<p><strong>URL:</strong> <a href="' + p.url + '">' + p.url + '</a></p>' +
    '<p><strong>Detected:</strong> ' + p.checked_at + '</p>' +
    '<hr><h3>AI Summary of Changes</h3>' +
    '<div>' + summary.replace(/\n/g, '<br>') + '</div>' +
    '<hr><p style="color:#666;font-size:12px;">Generated by your TOS Change Watcher workflow in n8n.</p>';

  results.push({
    json: {
      email_subject: 'TOS Change Alert: ' + p.page_name,
      email_body: body,
      url: p.url,
      page_name: p.page_name,
      summary: summary,
      checked_at: p.checked_at,
      new_content: p.new_content
    }
  });
}

return results;
